import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/** ====== Helpers ====== **/
const TYPE_MAP = [
    { label: "Thi công", value: "CONSTRUCTION" },
    { label: "Dịch vụ", value: "SERVICE" },
];

const STATUS_MAP = [
    { label: "Đang thực hiện", value: "ACTIVE" },
    { label: "Chờ duyệt/Ký", value: "PENDING" },
    { label: "Hoàn tất", value: "COMPLETED" },
    { label: "Hủy", value: "CANCELLED" },
];

const findLabel = (list, v) => list.find((x) => x.value === v)?.label || v || "-";

const fmtMoney = (n) =>
    (n ?? 0).toLocaleString("vi-VN", { maximumFractionDigits: 0 });

const parseMoney = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const digits = String(s).replace(/[^\d]/g, "");
    return Number(digits || 0);
};

const toISO = (d) => {
    if (!d) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
    const m = String(d).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[2]}-${m[1]}`;
    try {
        const dt = new Date(d);
        if (!isNaN(dt)) return dt.toISOString().slice(0, 10);
    } catch {}
    return "";
};

const badgeCls = (status) => {
    switch (status) {
        case "ACTIVE":
            return "bg-emerald-100 text-emerald-700";
        case "PENDING":
            return "bg-amber-100 text-amber-700";
        case "COMPLETED":
            return "bg-indigo-100 text-indigo-700";
        case "CANCELLED":
            return "bg-rose-100 text-rose-700";
        default:
            return "bg-slate-100 text-slate-700";
    }
};

/** ====== Page ====== **/
export default function Contracts() {
    const { user } = useAuth();
    const [rows, setRows] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [loading, setLoading] = useState(true);

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);

    const [form, setForm] = useState({
        contractCode: "",
        title: "",
        customerId: "",
        totalAmount: "",
        signedDate: "",
        dueDate: "",
        contractType: "CONSTRUCTION",
        status: "PENDING", // chỉ dùng khi EDIT
    });

    useEffect(() => {
        loadAll();
    }, []);

    async function loadAll() {
        setLoading(true);
        try {
            const [cRes, custRes] = await Promise.all([
                api.get("/api/contracts", { params: { page: 0, size: 20, sort: "id,desc" } }),
                api.get("/api/customers", { params: { page: 0, size: 100, sort: "name,asc" } }),
            ]);

            const list = Array.isArray(cRes.data) ? cRes.data : cRes.data?.content || [];
            setRows(
                list.map((x) => ({
                    id: x.id,
                    contractCode: x.contractCode,
                    title: x.title,
                    contractType: x.contractType,
                    customerId: x.customerId,
                    customerName: x.customerName,
                    signedDate: x.signedDate,
                    dueDate: x.dueDate,
                    totalAmount: x.totalAmount,
                    paidAmount: x.paidAmount,
                    remainingAmount: x.remainingAmount,
                    status: x.status,
                }))
            );

            const custList = Array.isArray(custRes.data) ? cRes.data : cRes.data?.content || [];
            setCustomers(custList.map((c) => ({ id: c.id, name: c.name })));
        } catch (e) {
            console.error(e);
            alert("Tải dữ liệu hợp đồng thất bại");
        } finally {
            setLoading(false);
        }
    }

    /** Modal controls */
    function openCreate() {
        setEditing(null);
        setForm({
            contractCode: autoCode(),
            title: "",
            customerId: "",
            totalAmount: "",
            signedDate: todayStr(),
            dueDate: "",
            contractType: "CONSTRUCTION",
            status: "PENDING",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            contractCode: row.contractCode || "",
            title: row.title || "",
            customerId: row.customerId || "",
            totalAmount: fmtMoney(row.totalAmount || 0),
            signedDate: toISO(row.signedDate) || "",
            dueDate: toISO(row.dueDate) || "",
            contractType: row.contractType || "CONSTRUCTION",
            status: row.status || "PENDING",
        });
        setShow(true);
    }

    /** Save */
    async function save(e) {
        e.preventDefault();

        try {
            if (editing) {
                // UPDATE: chỉ gửi field được phép sửa
                const payloadUpdate = {
                    title: form.title?.trim() || null,
                    contractType: form.contractType || null,
                    signedDate: toISO(form.signedDate) || null,
                    dueDate: toISO(form.dueDate) || null,
                    totalAmount: parseMoney(form.totalAmount) || null,
                    status: form.status || null,
                };
                await api.put(`/api/contracts/${editing.id}`, payloadUpdate);
            } else {
                // CREATE: backend tự sinh code, tự gán sales từ token, status mặc định
                const payloadCreate = {
                    title: form.title?.trim(),
                    contractType: form.contractType,
                    customerId: Number(form.customerId),
                    signedDate: toISO(form.signedDate) || null,
                    dueDate: toISO(form.dueDate) || null,
                    totalAmount: parseMoney(form.totalAmount),
                };
                await api.post("/api/contracts", payloadCreate);
            }

            setShow(false);
            await loadAll();
        } catch (err) {
            console.error("Save contract error:", err?.response || err);
            const data = err?.response?.data;
            let msg =
                data?.message ||
                data?.error ||
                (typeof data === "string" ? data : "") ||
                "Lưu hợp đồng thất bại";
            try {
                if (!msg && data) msg = JSON.stringify(data);
            } catch {}
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xóa hợp đồng ${row.contractCode}?`)) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await loadAll();
        } catch (err) {
            const data = err?.response?.data;
            alert(
                data?.message ||
                data?.error ||
                (typeof data === "string" ? data : "Xóa hợp đồng thất bại")
            );
        }
    }

    const customerOptions = useMemo(
        () => customers.map((c) => ({ value: String(c.id), label: c.name })),
        [customers]
    );

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold text-slate-900">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Theo dõi mã, loại, giá trị và trạng thái</p>
                </div>
                <button
                    onClick={openCreate}
                    className="px-4 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700 shadow"
                >
                    Thêm hợp đồng
                </button>
            </div>

            {/* List: tăng độ rộng card -> 2 cột trên màn lớn */}
            <div className="grid gap-6 sm:grid-cols-1 md:grid-cols-2 xl:grid-cols-2">
                {loading ? (
                    <div className="col-span-full text-slate-500">Đang tải…</div>
                ) : rows.length === 0 ? (
                    <div className="col-span-full text-slate-500">Chưa có hợp đồng</div>
                ) : (
                    rows.map((c) => (
                        <div
                            key={c.id}
                            className="rounded-2xl border border-indigo-100 bg-white p-5 shadow-sm hover:shadow-md transition"
                        >
                            <div className="flex items-start justify-between gap-3">
                                <div className="font-semibold text-slate-900 truncate">{c.contractCode || "(Không mã)"}</div>
                                <span className={`text-xs px-2 py-0.5 rounded-full ${badgeCls(c.status)}`}>
                  {findLabel(STATUS_MAP, c.status)}
                </span>
                            </div>

                            <div className="mt-1 text-sm text-slate-600 line-clamp-2">{c.title || "—"}</div>
                            <div className="mt-1 text-sm text-slate-500">
                                {findLabel(TYPE_MAP, c.contractType)} • Kh: {c.customerName || "—"}
                            </div>

                            {/* Số liệu: đảm bảo không tràn số */}
                            <div className="mt-4 grid grid-cols-3 gap-3">
                                <div className="rounded-xl bg-slate-50 p-3 min-w-0">
                                    <div className="text-xs text-slate-500">Giá trị</div>
                                    <div className="text-right font-semibold tabular-nums tracking-tight text-[15px] md:text-base truncate">
                                        {fmtMoney(c.totalAmount)} đ
                                    </div>
                                </div>
                                <div className="rounded-xl bg-slate-50 p-3 min-w-0">
                                    <div className="text-xs text-slate-500">Đã thu</div>
                                    <div className="text-right font-semibold tabular-nums tracking-tight text-[15px] md:text-base truncate">
                                        {fmtMoney(c.paidAmount)} đ
                                    </div>
                                </div>
                                <div className="rounded-xl bg-slate-50 p-3 min-w-0">
                                    <div className="text-xs text-slate-500">Còn lại</div>
                                    <div className="text-right font-semibold tabular-nums tracking-tight text-[15px] md:text-base truncate">
                                        {fmtMoney(c.remainingAmount)} đ
                                    </div>
                                </div>
                            </div>

                            <div className="mt-4 flex justify-end gap-2">
                                <button
                                    onClick={() => openEdit(c)}
                                    className="px-3 py-1.5 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                >
                                    Sửa
                                </button>
                                <button
                                    onClick={() => remove(c)}
                                    className="px-3 py-1.5 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                >
                                    Xóa
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl rounded-2xl bg-white shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShow(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {/* Mã (hiển thị cho biết) */}
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                <input
                                    value={form.contractCode}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, contractCode: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                    placeholder="VD: HD-20250828-9154"
                                />
                            </div>

                            {/* Khách hàng (chỉ khi tạo) */}
                            {!editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Khách hàng</label>
                                    <select
                                        value={form.customerId}
                                        onChange={(e) =>
                                            setForm((f) => ({ ...f, customerId: e.target.value }))
                                        }
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                        required
                                    >
                                        <option value="">— Chọn khách hàng —</option>
                                        {customerOptions.map((opt) => (
                                            <option key={opt.value} value={opt.value}>
                                                {opt.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            {/* Tiêu đề */}
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Tiêu đề</label>
                                <input
                                    value={form.title}
                                    onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                    placeholder="VD: Thi công nhà xưởng B - Phase 2"
                                />
                            </div>

                            {/* Tổng tiền */}
                            <div>
                                <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                <input
                                    inputMode="numeric"
                                    value={form.totalAmount}
                                    onChange={(e) =>
                                        setForm((f) => ({
                                            ...f,
                                            totalAmount: fmtMoney(parseMoney(e.target.value)),
                                        }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm text-right tabular-nums"
                                    placeholder="VD: 2.000.000.000"
                                    required
                                />
                            </div>

                            {/* Ngày ký */}
                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input
                                    type="date"
                                    value={form.signedDate}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, signedDate: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                    required
                                />
                            </div>

                            {/* Hạn */}
                            <div>
                                <label className="text-sm text-slate-600">Ngày hết hạn</label>
                                <input
                                    type="date"
                                    value={form.dueDate}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, dueDate: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                />
                            </div>

                            {/* Loại */}
                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select
                                    value={form.contractType}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, contractType: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                >
                                    {TYPE_MAP.map((t) => (
                                        <option key={t.value} value={t.value}>
                                            {t.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Trạng thái (chỉ khi sửa) */}
                            {editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                    <input
                                        inputMode="numeric"
                                        value={form.totalAmount}
                                        onChange={(e) =>
                                            setForm((f) => ({
                                                ...f,
                                                totalAmount: fmtMoney(parseMoney(e.target.value)),
                                            }))
                                        }
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm text-right tabular-nums"
                                        placeholder="VD: 2.000.000.000"
                                        required
                                    />
                                </div>
                            )}

                            <div className="md:col-span-2 flex justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Hủy
                                </button>
                                <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

/** ====== tiny utils ====== **/
function todayStr() {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
}
function autoCode() {
    const d = new Date();
    const seg = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(
        d.getDate()
    ).padStart(2, "0")}-${Math.floor(1000 + Math.random() * 9000)}`;
    return `HD-${seg}`;
}
